import {readFileSync, writeFileSync} from 'node:fs';
import {dirname, resolve} from 'node:path';
import {fileURLToPath} from 'node:url';

import {build} from 'esbuild';

const SCRIPT_PATH=fileURLToPath(import.meta.url);
const ROOT=resolve(dirname(SCRIPT_PATH),'..');
const OUTPUT=resolve(ROOT,'js/app.bundle.js');
const BANNER='/* Generated by scripts/build-classic-bundle.mjs from js/app.mjs. Do not edit directly. */';

export async function buildClassicBundle(){
  const result=await build({
    absWorkingDir:ROOT,
    entryPoints:['js/app.mjs'],
    outfile:'js/app.bundle.js',
    bundle:true,
    format:'iife',
    platform:'browser',
    target:['es2020'],
    charset:'utf8',
    legalComments:'none',
    minify:false,
    sourcemap:false,
    treeShaking:true,
    write:false,
    logLevel:'silent',
    banner:{js:BANNER},
  });
  if(result.outputFiles.length!==1) throw new Error('Expected exactly one classic browser bundle.');
  return result.outputFiles[0].text.replace(/\r\n?/gu,'\n');
}

function currentBundle(){
  try{ return readFileSync(OUTPUT,'utf8').replace(/\r\n?/gu,'\n'); }
  catch{ return ''; }
}

async function runCli(){
  const mode=process.argv[2]??'--write';
  if(!['--write','--check'].includes(mode)) throw new RangeError('Use --write or --check');
  const expected=await buildClassicBundle();
  const actual=currentBundle();
  if(mode==='--write'){
    if(actual!==expected) writeFileSync(OUTPUT,expected,'utf8');
    return;
  }
  if(actual!==expected){
    console.error('js/app.bundle.js ist nicht aktuell. Bitte npm run bundle ausführen.');
    process.exitCode=1;
  }
}

if(process.argv[1]&&resolve(process.argv[1])===SCRIPT_PATH) await runCli();
